import{_ as a,o as d,c as e,ai as r}from"./chunks/framework.SowO7O0D.js";const c=JSON.parse('{"title":"第十五课：基金定投","description":"","frontmatter":{},"headers":[],"relativePath":"guide/15定投.md","filePath":"guide/15定投.md","lastUpdated":0}'),n={name:"guide/15定投.md"};function s(l,t,o,i,h,p){return d(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="第十五课-基金定投" tabindex="-1">第十五课：基金定投 <a class="header-anchor" href="#第十五课-基金定投" aria-label="Permalink to “第十五课：基金定投”">​</a></h1><p>定投是&quot;懒人理财神器&quot;，特别适合上班族和新手。</p><h2 id="一、什么是定投" tabindex="-1">一、什么是定投？ <a class="header-anchor" href="#一、什么是定投" aria-label="Permalink to “一、什么是定投？”">​</a></h2><p><strong>定投 = 固定时间 + 固定金额 + 买同一只基金</strong></p><p>比如：每月8号发工资当天，花1000元买沪深300ETF。</p><h2 id="二、定投的原理" tabindex="-1">二、定投的原理 <a class="header-anchor" href="#二、定投的原理" aria-label="Permalink to “二、定投的原理”">​</a></h2><p><strong>核心逻辑</strong>：市场低时买得多，市场高时买得少，自动摊平成本。</p><table tabindex="0"><thead><tr><th>时间</th><th>股价</th><th>买入金额</th><th>买入股数</th></tr></thead><tbody><tr><td>第1个月</td><td>1元</td><td>1000元</td><td>1000股</td></tr><tr><td>第2个月</td><td>0.8元</td><td>1000元</td><td>1250股</td></tr><tr><td>第3个月</td><td>0.5元</td><td>1000元</td><td>2000股</td></tr><tr><td>第4个月</td><td>1元</td><td>1000元</td><td>1000股</td></tr></tbody></table><blockquote><p>平均成本 = 总投入 ÷ 总股数 = 4000 ÷ 5250 ≈ <strong>0.76元</strong></p></blockquote><p>第4个月涨回1元时，你的收益 = (1-0.76) × 5250 = <strong>1260元</strong>！</p><h2 id="三、定投为什么能赚钱" tabindex="-1">三、定投为什么能赚钱？ <a class="header-anchor" href="#三、定投为什么能赚钱" aria-label="Permalink to “三、定投为什么能赚钱？”">​</a></h2><p><strong>微笑曲线</strong>：即使你买在高点，只要坚持定投，市场反弹时就能盈利。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>        高点</span></span>
<span class="line"><span>       /    \\</span></span>
<span class="line"><span>      /      \\</span></span>
<span class="line"><span>     /   反弹  \\</span></span>
<span class="line"><span>    /__________\\  ← 回本+盈利</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><blockquote><p>💡 定投最怕的是：<strong>在低点停止定投，甚至割肉</strong>。</p></blockquote><h2 id="四、适合定投的品种" tabindex="-1">四、适合定投的品种 <a class="header-anchor" href="#四、适合定投的品种" aria-label="Permalink to “四、适合定投的品种”">​</a></h2><table tabindex="0"><thead><tr><th>品种</th><th>特点</th><th>适合人群</th></tr></thead><tbody><tr><td>沪深300ETF</td><td>稳健，长期向上</td><td>新手首选</td></tr><tr><td>创业板ETF</td><td>波动大，收益高</td><td>能承受波动的人</td></tr><tr><td>科创50ETF</td><td>高风险高回报</td><td>年轻人</td></tr><tr><td>指数基金</td><td>费率低</td><td>长期投资</td></tr></tbody></table><blockquote><p>💡 <strong>建议新手从沪深300ETF定投开始</strong>。</p></blockquote><h2 id="五、定投的频率" tabindex="-1">五、定投的频率 <a class="header-anchor" href="#五、定投的频率" aria-label="Permalink to “五、定投的频率”">​</a></h2><table tabindex="0"><thead><tr><th>频率</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>每周</td><td>成本更平滑</td><td>需要设置多次</td></tr><tr><td>每月</td><td>简单，适合工资族</td><td>稍粗略</td></tr></tbody></table><blockquote><p>大多数人选择<strong>每月定投</strong>，和发工资节奏一致。</p></blockquote><h2 id="六、定投的误区" tabindex="-1">六、定投的误区 <a class="header-anchor" href="#六、定投的误区" aria-label="Permalink to “六、定投的误区”">​</a></h2><blockquote><p>⚠️ <strong>定投不是稳赚不赔的！</strong></p></blockquote><table tabindex="0"><thead><tr><th>误区</th><th>真相</th></tr></thead><tbody><tr><td>&quot;随时买都行&quot;</td><td>高位开始定投，可能长期亏损</td></tr><tr><td>&quot;不用管，躺着赚钱&quot;</td><td>要定期检视，必要时止盈</td></tr><tr><td>&quot;金额固定不变&quot;</td><td>收入增加了，定投金额也应该增加</td></tr></tbody></table><h2 id="七、如何设置定投" tabindex="-1">七、如何设置定投？ <a class="header-anchor" href="#七、如何设置定投" aria-label="Permalink to “七、如何设置定投？”">​</a></h2><p>在券商/银行APP里：</p><ol><li>找到你想定投的ETF或基金</li><li>点击&quot;定投&quot; → 设置每月几号扣款</li><li>设置每期金额</li><li>确认</li></ol><h2 id="八、定投止盈技巧" tabindex="-1">八、定投止盈技巧 <a class="header-anchor" href="#八、定投止盈技巧" aria-label="Permalink to “八、定投止盈技巧”">​</a></h2><p>定投要学会<strong>止盈</strong>，不然坐过山车很痛苦：</p><table tabindex="0"><thead><tr><th>方法</th><th>说明</th></tr></thead><tbody><tr><td>目标止盈</td><td>收益率达到30%就卖出一半</td></tr><tr><td>分批止盈</td><td>涨到目标后，分3批卖出</td></tr><tr><td>高点回落止盈</td><td>从最高点回落15%就清仓</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>你计划每月定投2000元沪深300ETF，坚持3年。你觉得3年后大概能收益多少？</p></blockquote><hr><p><strong>下一课预告</strong>：投资工具学完了，下一课学习<strong>仓位管理</strong>——如何控制风险。</p>`,33)])])}const u=a(n,[["render",s]]);export{c as __pageData,u as default};
